def find_outliers_iqr(df, column):
    Q1 = df[column].quantile(0.25)
    Q3 = df[column].quantile(0.75)
    IQR = Q3 - Q1
    lower_bound = Q1 - 1.5 * IQR
    upper_bound = Q3 + 1.5 * IQR
    outliers = df[(df[column] < lower_bound) | (df[column] > upper_bound)]
    return outliers, lower_bound, upper_bound

for col in numerical_cols_updated:
    outliers, lower_bound, upper_bound = find_outliers_iqr(df_health, col)
    print(f"\n--- Outliers for {col} ---")
    print(f"Lower Bound: {lower_bound:.2f}, Upper Bound: {upper_bound:.2f}")
    print(f"Number of outliers: {len(outliers)}")
    if len(df_health) > 0:
        percentage_outliers = (len(outliers) / len(df_health)) * 100
        print(f"Percentage of outliers: {percentage_outliers:.2f}%")
    if not outliers.empty:
        display(outliers.head())
    else:
        print("No outliers found.")

"""Capping Outlier menggunakan IQR"""

df_health_cleaned = df_health.copy() # Create a copy to store cleaned data

for col in numerical_cols_updated:
    Q1 = df_health_cleaned[col].quantile(0.25)
    Q3 = df_health_cleaned[col].quantile(0.75)
    IQR = Q3 - Q1
    lower_bound = Q1 - 1.5 * IQR
    upper_bound = Q3 + 1.5 * IQR

    # Cap outliers: values below lower_bound become lower_bound, values above upper_bound become upper_bound
    df_health_cleaned[col] = np.where(df_health_cleaned[col] < lower_bound, lower_bound, df_health_cleaned[col])
    df_health_cleaned[col] = np.where(df_health_cleaned[col] > upper_bound, upper_bound, df_health_cleaned[col])

print("Outliers have been capped for all numerical columns.")
display(df_health_cleaned.head())

