def iterative_vif_removal(X, threshold=10):
    """
    Hapus fitur dengan VIF tertinggi satu per satu sampai semua VIF
    di bawah threshold.

    Kenapa satu per satu?
    Karena VIF bersifat dinamis, yakni setelah satu fitur dihapus,
    VIF fitur lain bisa berubah drastis!
    """
    X_clean = X.copy()
    iteration = 1
    removed_features = []

    print("=" * 60)
    print("ITERATIVE VIF REMOVAL")
    print(f"Threshold VIF : {threshold}")
    print(f"Fitur awal    : {X.shape[1]}")
    print("=" * 60)

    while True:
        # Hitung VIF semua fitur yang tersisa
        vif_df = calc_vif(X_clean)

        print(f"\nITERASI {iteration} — {X_clean.shape[1]} fitur tersisa")
        print(vif_df.to_string(index=False))

        # Check apakah masih ada VIF > threshold
        max_vif = vif_df['VIF'].max()
        max_feature = vif_df.loc[vif_df['VIF'].idxmax(), 'variables']

        if max_vif <= threshold:
            print(f"\nSELESAI! Semua VIF sudah di bawah {threshold}")
            break

        # Hapus fitur dengan VIF tertinggi
        print(f"\nHapus: '{max_feature}' (VIF: {max_vif:.2f})")
        print("-" * 60)
        X_clean = X_clean.drop(columns=[max_feature])
        removed_features.append(max_feature)
        iteration += 1

    return X_clean, removed_features

# Jalankan iterative VIF removal
X_clean, removed_features = iterative_vif_removal(X, threshold=10)

