"""> Hyperparameter Tuning with GridSearchCV (Random Forest)

"""

from sklearn.model_selection import GridSearchCV

# Define the parameter grid for RandomForestClassifier
param_grid = {
    'n_estimators': [100, 200, 300],  # Number of trees in the forest
    'max_features': ['sqrt', 'log2'], # Number of features to consider when looking for the best split
    'max_depth': [None, 10, 20],      # Maximum depth of the tree
    'min_samples_leaf': [1, 2, 4]     # Minimum number of samples required to be at a leaf node
}

# Initialize the RandomForestClassifier with class weights
rf_model = RandomForestClassifier(random_state=42, class_weight='balanced')

# Initialize GridSearchCV
# Using 'f1_weighted' as the scoring metric due to class imbalance
grid_search = GridSearchCV(estimator=rf_model,
                           param_grid=param_grid,
                           cv=5,                  # 5-fold cross-validation
                           scoring='f1_weighted', # Metric to optimize
                           n_jobs=-1,             # Use all available cores
                           verbose=2)

print("Starting GridSearchCV...")
# Fit GridSearchCV to the training data
grid_search.fit(X_train_scaled, y_train)
print("GridSearchCV finished.")

print("Best parameters found: ", grid_search.best_params_)
print("Best F1-weighted score found: {:.4f}".format(grid_search.best_score_))

# Get the best model
best_rf_model = grid_search.best_estimator_

print("\nEvaluating the best Random Forest model on the test set...")
# Make predictions with the best model
y_pred_best_rf = best_rf_model.predict(X_test_scaled)

# Evaluate the best model
print("\n--- Best Random Forest Classification Report ---")
print(classification_report(y_test, y_pred_best_rf, target_names=['low risk', 'mid risk', 'high risk']))

print("\n--- Best Random Forest Confusion Matrix ---")
conf_matrix_best_rf = confusion_matrix(y_test, y_pred_best_rf)
display(pd.DataFrame(conf_matrix_best_rf,
                     index=['Actual Low Risk', 'Actual Mid Risk', 'Actual High Risk'],
                     columns=['Predicted Low Risk', 'Predicted Mid Risk', 'Predicted High Risk']))

print("\n--- Best Random Forest Accuracy Score ---")
accuracy_best_rf = accuracy_score(y_test, y_pred_best_rf)
print(f"Accuracy: {accuracy_best_rf:.4f}")

# Plotting the confusion matrix for the best Random Forest
plt.figure(figsize=(8, 6))
sns.heatmap(conf_matrix_best_rf, annot=True, fmt='d', cmap='Blues',
            xticklabels=['low risk', 'mid risk', 'high risk'],
            yticklabels=['low risk', 'mid risk', 'high risk'])
plt.title('Best Random Forest Confusion Matrix (Hyperparameter Tuned)')
plt.xlabel('Predicted')
plt.ylabel('Actual')
plt.show()

